import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

import java.util.Scanner;

public class XSSFixedCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userName = scanner.nextLine();

        // Encode user input to prevent XSS attacks
        HTMLEntityCodec htmlEncoder = new HTMLEntityCodec();
        String encodedUserName = htmlEncoder.encodeForHTML(userName);

        System.out.println("Hello, " + encodedUserName + "!"); // Output sanitized user input

        scanner.close();
    }
}

